SELECT job.id_ as id_, job.type_ as type_, job.handler_type_ as handler_type_, job.handler_cfg_ as handler_cfg_, job.exception_msg_ as exception_message_, job.create_time_ as create_time_, job.element_id_ as element_id_, job.process_instance_id_ as process_instance_id_, job.proc_def_id_ as proc_def_id_, def.key_ as key_ FROM ${prefix}ACT_RU_DEADLETTER_JOB as job JOIN ${prefix}ACT_RE_PROCDEF as def ON job.proc_def_id_ = def.id_
LEFT JOIN ${prefix}ACT_RE_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_
AND def.key_ = #{definitionKey}
AND job.create_time_ >= #{startedAfter}
AND def.deployment_id_ IN ( SELECT id_ FROM ${prefix}ACT_RE_DEPLOYMENT ORDER BY deploy_time_ DESC LIMIT #{latestDeployments} )
ORDER BY job.create_time_ DESC

SELECT job.id_ as job_id_, job.type_ as type_, job.handler_type_ as handler_type_, job.handler_cfg_ as handler_cfg_, job.exception_msg_ as exception_message_, job.create_time_ as create_time_, job.element_id_ as element_id_, job.process_instance_id_ as process_instance_id_, job.proc_def_id_ as proc_def_id_, def.key_ as key_, ba.bytes_ as exception_stacktrace_ FROM ${prefix}ACT_RU_DEADLETTER_JOB as job JOIN ${prefix}ACT_RE_PROCDEF as def ON job.proc_def_id_ = def.id_ LEFT JOIN ${prefix}ACT_GE_BYTEARRAY as ba ON job.exception_stack_id_ = ba.id_
LEFT JOIN ${prefix}ACT_RE_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_
AND job.id_ = #{jobId}
AND def.key_ = #{definitionKey}
AND job.create_time_ >= #{startedAfter}
AND def.deployment_id_ IN ( SELECT id_ FROM ${prefix}ACT_RE_DEPLOYMENT ORDER BY deploy_time_ DESC LIMIT #{latestDeployments} )
ORDER BY job.create_time_ DESC

